378→public fun ASTNode.isValOrVarKeyword(): Boolean = elementType == VAL_KEYWORD || elementType == VAR_KEYWORD || elementType == VARARG_KEYWORD
379→
380→/**
381→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
382→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
383→ */
384→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
385→    val sequence =
386→        if (isLeaf()) {
387→            sequenceOf(this)
388→        } else {
389→            emptySequence()
390→        }
391→    return sequence.plus(leaves(forward))
392→}
