394→/**
395→ * Get all leaves on the same line as the given node including the whitespace indentation. Note that the whitespace indentation may start
396→ * with zero or more newline characters.
397→ */
398→public fun ASTNode.leavesOnLine(): Sequence<ASTNode> {
399→    val lastLeafOnLineOrNull = getLastLeafOnLineOrNull()
400→    return getFirstLeafOnLineOrSelf()
401→        .leavesIncludingSelf()
402→        .takeWhile { lastLeafOnLineOrNull == null || it.prevLeaf() != lastLeafOnLineOrNull }
403→}
404→
405→internal fun ASTNode.getFirstLeafOnLineOrSelf() = prevLeaf { it.textContains('\n') || it.prevLeaf() == null }!!
406→
407→internal fun ASTNode.getLastLeafOnLineOrNull() = nextLeaf { it.textContains('\n') }?.prevLeaf()
408→
409→/**
410→ * Get the total length of all leaves on the same line as the given node including the whitespace indentation but excluding all leading
411→ * newline characters in the whitespace indentation.
412→ */
413→public fun ASTNode.lineLengthWithoutNewlinePrefix(): Int =
414→    leavesOnLine()
415→        .joinToString(separator = "") { it.text }
416→        // If a line is preceded by a blank line then the ident contains multiple newline chars
417→        .dropWhile { it == '\n' }
418→        // In case the last element on the line would contain a newline then only include chars before that newline. Note that this should
419→        // not occur if the AST is parsed correctly
420→        .takeWhile { it != '\n' }
421→        .length
