127→private fun ASTNode.getElementsPerLine(): List<ParsedLine> {
128→    val parsedLines = mutableListOf<ParsedLine>()
129→    val lines = text.split("\n")
130→    var offset = 0
131→    for (line in lines) {
132→        val elements = mutableListOf<ASTNode>()
133→        var el = psi.findElementAt(offset)?.node
134→        while (el != null && el.startOffset < offset + line.length) {
135→            elements.add(el)
136→            el = el.nextLeaf()
137→        }
138→        parsedLines.add(ParsedLine(line, offset, elements))
139→        offset += line.length + 1 // +1 for the newline which is stripped due to the splitting of the lines
140→    }
141→    return parsedLines
142→}
