192→        // binary search for min(arr[l] >= vmin)
193→        var l = 0
194→        while (l < r) {
195→            val m = (r + l) / 2
196→            if (vmax < arr[m]) {
197→                r = m - 1
198→            } else if (arr[m] < vmin) {
199→                l = m + 1
